/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements recipient validation (phone number format), message formatting
 * with character-limit awareness, and in-memory storage of sent messages
 * for inspection (swap with a real SMS gateway for production).
 *
 * Implements the NotificationAdapter interface as required by the
 * notification system architecture.
 *
 * NOTE: The user preferences model (user-preferences.ts) currently only
 * supports email preferences. It needs to be extended to support per-channel
 * preferences (including SMS opt-in, frequency, and subscribed categories)
 * before SMS can be gated by user preferences. See TODO below.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationChannel, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  fromNumber: string;
}

const defaultSmsConfig: SmsConfig = {
  fromNumber: '+10000000000',
};

/**
 * A formatted SMS message ready for delivery.
 */
export interface FormattedSms {
  from: string;
  to: string;
  body: string;
}

/**
 * SMS character limit. Messages longer than this are truncated.
 */
const SMS_MAX_LENGTH = 160;

/**
 * Template definitions keyed by notification type.
 * Each template receives the payload and returns a concise SMS body.
 */
type SmsTemplateRenderer = (payload: NotificationPayload) => string;

const smsTemplates: Record<NotificationType, SmsTemplateRenderer> = {
  order_confirmation(payload) {
    return `TaskFlow Pro: ${payload.subject}. ${payload.body}`;
  },
  order_status_update(payload) {
    return `TaskFlow Pro: ${payload.subject}. ${payload.body}`;
  },
  user_welcome(payload) {
    return `Welcome to TaskFlow Pro! ${payload.body}`;
  },
  user_updated(payload) {
    return `TaskFlow Pro: ${payload.subject}. ${payload.body}`;
  },
};

// E.164 format: + followed by 1-15 digits
const PHONE_REGEX = /^\+[1-9]\d{1,14}$/;

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: FormattedSms[] = [];
  private config: SmsConfig;

  constructor(config: SmsConfig = defaultSmsConfig) {
    this.config = config;
  }

  /**
   * Validate that a recipient string is a well-formed phone number (E.164).
   */
  validateRecipient(recipient: string): string | null {
    if (!recipient || !PHONE_REGEX.test(recipient)) {
      return `Invalid phone number: ${recipient}`;
    }
    return null;
  }

  /**
   * Format the notification payload into an SMS message using the
   * template for the notification type. Truncates to SMS_MAX_LENGTH.
   */
  formatMessage(payload: NotificationPayload): FormattedSms {
    const renderer = smsTemplates[payload.type];
    let body = renderer(payload);

    if (body.length > SMS_MAX_LENGTH) {
      body = body.substring(0, SMS_MAX_LENGTH - 3) + '...';
    }

    return {
      from: this.config.fromNumber,
      to: payload.recipient,
      body,
    };
  }

  /**
   * Send a notification through the SMS channel.
   * Validates the recipient, formats the message, and delivers.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Preparing SMS to ${payload.recipient}: ${payload.subject}`);

    // Validate recipient
    const validationError = this.validateRecipient(payload.recipient);
    if (validationError) {
      this.logger.warn(`Validation failed for ${payload.id}: ${validationError}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: validationError,
      };
    }

    // Format message
    const sms = this.formatMessage(payload);

    // Deliver (in-memory store; replace with SMS gateway call in production)
    this.sentMessages.push(sms);

    this.logger.info(
      `SMS delivered: ${payload.id} from ${sms.from} to ${sms.to}`,
    );

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
    };
  }

  /**
   * Get all messages sent through this adapter (for testing).
   */
  getSentMessages(): FormattedSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history (for testing).
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'sms',
    recipient: '+14155551234',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter({ fromNumber: '+10000000000' });
  });

  describe('channel', () => {
    it('should identify as sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('validateRecipient', () => {
    it('should accept valid E.164 phone numbers', () => {
      expect(adapter.validateRecipient('+14155551234')).toBeNull();
      expect(adapter.validateRecipient('+442071234567')).toBeNull();
      expect(adapter.validateRecipient('+861234567890')).toBeNull();
    });

    it('should reject empty string', () => {
      expect(adapter.validateRecipient('')).toContain('Invalid phone number');
    });

    it('should reject number without + prefix', () => {
      expect(adapter.validateRecipient('14155551234')).toContain('Invalid phone number');
    });

    it('should reject number with spaces', () => {
      expect(adapter.validateRecipient('+1 415 555 1234')).toContain('Invalid phone number');
    });

    it('should reject number with dashes', () => {
      expect(adapter.validateRecipient('+1-415-555-1234')).toContain('Invalid phone number');
    });

    it('should reject number starting with +0', () => {
      expect(adapter.validateRecipient('+04155551234')).toContain('Invalid phone number');
    });

    it('should reject non-numeric characters', () => {
      expect(adapter.validateRecipient('+1415abc1234')).toContain('Invalid phone number');
    });
  });

  describe('formatMessage', () => {
    it('should format order confirmation message', () => {
      const payload = makePayload();
      const sms = adapter.formatMessage(payload);

      expect(sms.from).toBe('+10000000000');
      expect(sms.to).toBe('+14155551234');
      expect(sms.body).toContain('TaskFlow Pro');
      expect(sms.body).toContain('Widget x2');
    });

    it('should format user_welcome message', () => {
      const payload = makePayload({
        type: 'user_welcome',
        subject: 'Welcome!',
        body: 'Your account is ready.',
      });
      const sms = adapter.formatMessage(payload);

      expect(sms.body).toContain('Welcome to TaskFlow Pro');
      expect(sms.body).toContain('Your account is ready');
    });

    it('should truncate messages longer than 160 characters', () => {
      const longBody = 'A'.repeat(200);
      const payload = makePayload({ body: longBody });
      const sms = adapter.formatMessage(payload);

      expect(sms.body.length).toBeLessThanOrEqual(160);
      expect(sms.body).toMatch(/\.\.\.$/);
    });

    it('should not truncate messages within 160 characters', () => {
      const payload = makePayload({
        type: 'user_welcome',
        subject: 'Hi',
        body: 'Short message.',
      });
      const sms = adapter.formatMessage(payload);

      expect(sms.body).not.toMatch(/\.\.\.$/);
    });
  });

  describe('send', () => {
    it('should send successfully for valid phone number', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.error).toBeUndefined();
    });

    it('should store sent message on success', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+14155551234');
      expect(sent[0]?.from).toBe('+10000000000');
      expect(sent[0]?.body).toContain('Widget x2');
    });

    it('should fail for invalid phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-number' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should not store message on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ id: 'n-1', recipient: '+14155551111' }));
      await adapter.send(makePayload({ id: 'n-2', recipient: '+14155552222' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return a copy of sent messages', async () => {
      await adapter.send(makePayload());
      const first = adapter.getSentMessages();
      const second = adapter.getSentMessages();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear all sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('custom config', () => {
    it('should use custom fromNumber', async () => {
      const customAdapter = new SmsAdapter({ fromNumber: '+19875551234' });
      await customAdapter.send(makePayload());

      const sent = customAdapter.getSentMessages();
      expect(sent[0]?.from).toBe('+19875551234');
    });

    it('should use default config when none provided', () => {
      const defaultAdapter = new SmsAdapter();
      expect(defaultAdapter.channel).toBe('sms');
    });
  });
});

